 36→const toCount = (value: unknown): number | null => {
 37→  const parsed = Number(value);
 38→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 39→};
 40→
 41→const resolveCount = (
 42→  aggregate: Array<{count?: number}> | undefined,
 43→  fallback?: number,
 44→): number => {
 45→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 46→};
