 34→
 35→export function RepostModal({
 36→  visible,
 37→  sourceJournalId,
 38→  title,
 39→  authorName,
 40→  authorAvatar,
 41→  onClose,
 42→}: RepostModalProps) {
 43→  const {session} = useAuth();
 44→  const {colors} = useTheme();
 45→  const token = session?.access_token ?? '';
 46→  const [caption, setCaption] = useState('');
 47→  const [submitting, setSubmitting] = useState(false);
 48→
 49→  const handleRepost = async () => {
 50→    if (!token) {
 51→      Alert.alert('Error', 'Please log in to repost.');
 52→      return;
 53→    }
 54→    setSubmitting(true);
 55→    try {
 56→      await socialApi.createRepost(token, {
 57→        sourceJournalId,
 58→        caption: caption.trim() || undefined,
 59→      });
 60→      queryClient.invalidateQueries({queryKey: ['feed']});
 61→      queryClient.invalidateQueries({queryKey: ['profileWritings']});
 62→      setCaption('');
 63→      onClose();
 64→      Alert.alert('Reposted', 'Post was reposted to your feed.');
 65→    } catch (e) {
 66→      Alert.alert('Repost failed', e instanceof Error ? e.message : 'Could not repost. Please try again.');
 67→    } finally {
 68→      setSubmitting(false);
 69→    }
 70→  };
 71→
 72→  const displayTitle = title
 73→    ? title.length > 80 ? title.slice(0, 80) + '...' : title
 74→    : 'Untitled Post';
 75→
 76→  return (
 77→    <Modal
 78→      visible={visible}
 79→      animationType="slide"
 80→      presentationStyle="pageSheet"
 81→      onRequestClose={onClose}>
 82→      <SafeAreaView style={[styles.container, {backgroundColor: colors.bgPrimary}]}>
 83→        {/* Header */}
 84→        <View style={[styles.header, {borderBottomColor: colors.borderCard}]}>
 85→          <Text style={[styles.headerTitle, {color: colors.textHeading}]}>
 86→            Repost
 87→          </Text>
 88→          <Pressable onPress={onClose} hitSlop={12}>
 89→            <XIcon size={22} color={colors.textMuted} />
 90→          </Pressable>
 91→        </View>
 92→
 93→        <KeyboardAvoidingView
 94→          style={styles.flex}
 95→          behavior={Platform.OS === 'ios' ? 'padding' : undefined}>
 96→          <View style={styles.body}>
 97→            {/* Original post preview */}
 98→            <View style={[styles.preview, {backgroundColor: colors.bgSecondary, borderColor: colors.borderCard}]}>
 99→              <View style={styles.previewRow}>
100→                <Avatar uri={authorAvatar} name={authorName} size={28} />
101→                <Text style={[styles.previewAuthor, {color: colors.textPrimary}]} numberOfLines={1}>
102→                  {authorName || 'Unknown author'}
103→                </Text>
104→              </View>
105→              <Text style={[styles.previewTitle, {color: colors.textSecondary}]} numberOfLines={2}>
106→                {displayTitle}
107→              </Text>
108→            </View>
109→
110→            {/* Caption input */}
111→            <Text style={[styles.label, {color: colors.textMuted}]}>
112→              Add your thoughts (optional)
113→            </Text>
114→            <TextInput
115→              value={caption}
116→              onChangeText={text => text.length <= CAPTION_MAX && setCaption(text)}
117→              placeholder="Write a caption..."
118→              placeholderTextColor={colors.textFaint}
119→              style={[
120→                styles.captionInput,
121→                {
122→                  backgroundColor: colors.bgSecondary,
123→                  borderColor: colors.borderCard,
124→                  color: colors.textPrimary,
125→                },
126→              ]}
127→              maxLength={CAPTION_MAX}
128→              multiline
129→            />
130→            <Text
131→              style={[
132→                styles.charCount,
133→                {color: caption.length >= CAPTION_MAX ? colors.danger : colors.textFaint},
134→              ]}>
135→              {caption.length}/{CAPTION_MAX}
136→            </Text>
137→
138→            {/* Repost button */}
139→            <PrimaryButton
140→              label={submitting ? 'Reposting...' : 'Repost to feed'}
141→              onPress={handleRepost}
142→              disabled={submitting}
143→            />
144→          </View>
145→        </KeyboardAvoidingView>
146→      </SafeAreaView>
147→    </Modal>
148→  );
149→}
