128→    mutationFn: async () => {
129→      if (!token) throw new Error('Please log in to bookmark.');
130→      return socialApi.toggleBookmark(token, {journalId});
131→    },
132→    onSuccess: () => {
133→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
134→      queryClient.invalidateQueries({queryKey: ['feed']});
135→    },
136→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
137→  });
138→
139→  const repostMutation = useMutation({
140→    mutationFn: async () => {
