170→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
171→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
172→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
173→          </View>
174→        </View>
175→      </SafeAreaView>
176→    );
177→  }
178→
179→  if (detailQuery.isError) {
180→    return (
181→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
182→        <View style={styles.contentPadding}>
183→          <Text style={[styles.errorText, {color: colors.danger}]}>
